INSERT INTO wildlife_species (slug, name, scientific_name, description, class_type, conservation_status, nepal_status, habitat, elevation_range, estimated_population, is_endemic, is_featured, fun_facts) VALUES
('olive-barb', 'Olive Barb', 'Puntius sarana', 'A medium-sized cyprinid found in rivers and lakes across the Terai and foothills of Nepal.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Rivers, lakes, and ponds in Terai and lower hills', '100-1500m', '500000', false, false, 'Olive barb is an important food fish widely cultivated in Nepali aquaculture.'),
('stigma-barb', 'Stigma Barb', 'Puntius stigma', 'A small cyprinid with a distinctive dark spot on its flank, common in hill streams.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Clear hill streams and rivers', '200-1500m', '300000', false, false, 'The stigma barb gets its name from the dark blotch behind its gill opening.'),
('chola-barb', 'Chola Barb', 'Puntius chola', 'A small freshwater barb found in slow-moving waters and flooded fields of the Terai.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Ponds, ditches, and slow rivers in Terai', '50-800m', '200000', false, false, 'Chola barb is often caught using traditional bamboo traps by local fishermen.'),
('green-carplet', 'Green Carplet', 'Puntius gonionotus', 'A silvery-green cyprinid common in rivers and floodplains of southern Nepal.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Rivers, canals, and floodplain lakes', '50-1000m', '400000', false, false, 'Green carplet is a major contributor to inland fisheries in the Terai region.'),
('spotted-danio', 'Spotted Danio', 'Rasbora daniconius', 'A slender, silvery fish with a dark lateral stripe, found in clear hill streams.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Clear streams and rivers with moderate current', '200-1800m', '350000', false, false, 'Spotted danio is popular among aquarium hobbyists for its active schooling behavior.'),
('elangbata-rasbora', 'Elangbata Rasbora', 'Rasbora elangbata', 'A small cyprinid found in clear streams of the eastern Nepal hills.', 'FISH', 'DATA_DEFICIENT', 'COMMON', 'Clear hill streams with rocky substrate', '300-1200m', '50000', false, false, 'This species is named after the Elangbata stream type locality in Nepal.'),
('giant-headsnakehead', 'Giant Headsnakehead', 'Channa marulia', 'A large predatory fish with a snake-like head, found in rivers and floodplains.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Rivers, ponds, and flooded fields', '50-1200m', '300000', false, false, 'Giant snakehead can breathe atmospheric air using a labyrinth organ.'),
('dwarf-snakehead', 'Dwarf Snakehead', 'Channa gachua', 'A small snakehead species found in hill streams and wetlands of Nepal.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Streams, ditches, and wetlands', '100-2000m', '250000', false, false, 'Dwarf snakehead is known for its aggressive territorial behavior during breeding.'),
('striped-snakehead', 'Striped Snakehead', 'Channa striata', 'A medium snakehead with dark vertical bands, common in lowland waters.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Ponds, rivers, and marshes in Terai', '50-800m', '400000', false, false, 'Striped snakehead is one of the most commercially important food fish in Nepal.'),
('rohu', 'Rohu', 'Labeo rohita', 'A large cyprinid and one of the most important freshwater food fish in South Asia.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Rivers, lakes, and aquaculture ponds', '50-1500m', '600000', true, false, 'Rohu is the national fish of Bangladesh and widely cultured across Nepal.'),
('kalibaush', 'Kalibaush', 'Labeo calbasu', 'A large dark-colored carp found in rivers and deep pools of Nepal.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Deep rivers and reservoirs', '50-1200m', '200000', false, false, 'Kalibaush is prized for its taste and is considered a premium food fish.'),
('hill-trout', 'Hill Trout', 'Garra gotyla', 'A torrent-dwelling cyprinid with a sucker mouth, adapted to fast-flowing hill streams.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Fast-flowing rocky hill streams', '300-2500m', '300000', false, false, 'Hill trout uses its modified lower lip as a suction cup to cling to rocks.'),
('mahi-mahi-barb', 'Lamba Garra', 'Garra lamta', 'A streamlined cyprinid found in moderate to fast-flowing streams.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Hill streams with rocky substrate', '200-1800m', '200000', false, false, 'Garra species are important indicators of stream health in Nepal.'),
('almora-himilayan-barb', 'Almora Himalayan Barb', 'Bangana almorae', 'A rare cyprinid endemic to the Kali Gandaki and associated drainages.', 'FISH', 'VULNERABLE', 'COMMON', 'Cold mountain rivers', '800-2000m', '15000', false, false, 'This species is named after the Almora district in Uttarakhand near the Nepal border.'),
('snow-trout-richardson', 'Richardson Snow Trout', 'Schizothorax richardsonii', 'A cold-water cyprinid adapted to glacial rivers and high-altitude streams.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Cold mountain rivers and glacial streams', '1500-4000m', '250000', false, false, 'Richardson snow trout can survive in near-freezing water temperatures.'),
('plagiostomus-snow-trout', 'Plagiostomus Snow Trout', 'Schizothorax plagiostomus', 'A medium-sized snow trout found in rivers of the Karnali and Mahakali basins.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Rivers and large streams in western Nepal', '500-3000m', '150000', false, false, 'This species is an important component of subsistence fisheries in western Nepal.'),
('esox-snow-trout', 'Esox Snow Trout', 'Schizothorax esocinus', 'A large snow trout found in deep pools of Himalayan rivers.', 'FISH', 'NEAR_THREATENED', 'COMMON', 'Deep pools in large rivers', '800-2500m', '80000', false, false, 'The largest snow trout species, reaching over 50cm in length.'),
('double-lip-carp', 'Double Lip Carp', 'Crossocheilus diplochilus', 'A bottom-dwelling cyprinid with a distinctive double-ridged upper lip.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Clear rocky streams and rivers', '300-2000m', '180000', false, false, 'This species grazes algae from rocks using its specialized mouth structure.'),
('tibetan-carp', 'Tibetan Carp', 'Gymnocypris fecunda', 'A high-altitude cyprinid adapted to the extreme conditions of trans-Himalayan waters.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'High-altitude lakes and rivers', '3500-5000m', '50000', false, false, 'Tibetan carp is one of the few fish that thrive above 4000m in Nepal.'),
('jayensis-raspbora', 'Jayensis Raspbora', 'Aspidoparia jayensis', 'A small cyprinid found in streams and rivers of the middle hills.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Rivers and streams with moderate current', '200-1500m', '120000', false, false, 'This species is named after the Jayanti River in eastern Nepal.'),
('stinging-catfish', 'Stinging Catfish', 'Heteropneustes fossilis', 'A small air-breathing catfish with a venomous pectoral spine, found in warm waters.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Ponds, ditches, and slow rivers', '50-600m', '300000', false, false, 'The stinging catfish can survive out of water for extended periods by breathing air.'),
('walking-catfish', 'Walking Catfish', 'Clarias batrachus', 'An air-breathing catfish capable of moving overland between water bodies.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Ponds, rice paddies, and slow streams', '50-500m', '250000', false, false, 'Walking catfish can use its rigid pectoral fins to travel across wet land.'),
('magur', 'Magur', 'Clarias magur', 'A large air-breathing catfish important in Nepali cuisine and aquaculture.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Ponds, rivers, and flooded fields', '50-800m', '350000', false, false, 'Magur is believed to have medicinal properties and is fed to patients recovering from illness.'),
('striped-catfish', 'Striated Catfish', 'Mystus vittatus', 'A small to medium catfish with dark longitudinal stripes along its body.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Rivers, ponds, and streams', '50-1200m', '200000', false, false, 'Striped catfish is commonly caught using set lines by rural fishermen.'),
('bleekers-catfish', 'Bleeker Catfish', 'Mystus bleekeri', 'A medium-sized catfish found in rivers and large streams of the Terai.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Rivers and large streams', '50-800m', '150000', false, false, 'This species is named after the Dutch ichthyologist Pieter Bleeker.'),
('boo-catfish', 'Boo Catfish', 'Mystus cavasius', 'A small catfish with a distinctive dark blotch at the dorsal fin base.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Ponds, rivers, and canals', '50-1000m', '200000', false, false, 'Boo catfish is one of the most abundant catfish species in Nepali lowlands.'),
('wallago', 'Wallago', 'Wallago attu', 'A large predatory catfish with a broad flat head, apex predator in rivers.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Large rivers and reservoirs', '50-1000m', '100000', true, false, 'Wallago attu can grow over 2 meters long and is the top predator in many Nepali rivers.'),
('smaller-wallago', 'Leeri Wallago', 'Wallago leeri', 'A smaller wallago species found in rivers of the eastern Terai.', 'FISH', 'NEAR_THREATENED', 'COMMON', 'Rivers with sandy substrate', '50-600m', '30000', false, false, 'Leeri wallago is becoming increasingly rare due to habitat degradation.'),
('rita-catfish', 'Rita', 'Rita rita', 'A medium-sized catfish with a bony head shield, found in turbid rivers.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Large rivers with muddy substrate', '50-800m', '150000', false, false, 'Rita catfish has extremely hard cranial bones that protect it from predators.'),
('giant-catfish', 'Aor', 'Sperata aor', 'A large catfish with a deeply forked tail, important in commercial fisheries.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Large rivers and deep pools', '50-600m', '120000', false, false, 'Aor catfish can reach lengths exceeding 1.5 meters in large river systems.'),
('bagarius-catfish', 'Goonch', 'Bagarius bagarius', 'A large bizarre-looking catfish with a flattened head, found in turbid rivers.', 'FISH', 'VULNERABLE', 'RARE', 'Deep pools in large rivers', '100-800m', '10000', false, false, 'Goonch is a feared predator in some rivers and was implicated in attacks on humans.'),
('yarrelli-bagarius', 'Yarrelli Goonch', 'Bagarius yarrelli', 'A giant bagarius catfish, the largest member of its genus.', 'FISH', 'ENDANGERED', 'RARE', 'Large deep rivers with strong currents', '100-600m', '5000', false, false, 'Yarrelli goonch is one of the rarest large catfish in South Asia.'),
('almora-loach', 'Almora Loach', 'Botia almorhae', 'A small striped loach found in hill streams with clear water and rocky substrate.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Hill streams with rocky bottoms', '300-2000m', '150000', false, false, 'Almora loach is named after the Almora district in the Kumaon hills.'),
('rostrata-loach', 'Rostrata Loach', 'Botia rostrata', 'A medium-sized loach with a pointed snout, found in fast-flowing streams.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Fast-flowing rocky streams', '200-1500m', '100000', false, false, 'Rostrata loach burrows into sandy substrate to escape predators.'),
('striped-loach', 'Striped Loach', 'Botia striata', 'A small loach with distinctive dark vertical bands on a pale body.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Clear hill streams', '200-1200m', '120000', false, false, 'Striped loach is a popular species among aquarium enthusiasts worldwide.'),
('beavannagar-loach', 'Beavannagar Loach', 'Schistura beavannagarensis', 'A small stone loach found in streams of the central Nepal hills.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Small streams with rocky substrate', '300-1800m', '80000', false, false, 'This species was first described from Beavannagar in the Kathmandu valley.'),
('scaturigina-loach', 'Scaturigina Loach', 'Schistura scaturigina', 'A tiny loach inhabiting spring-fed streams in the middle hills.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Spring-fed streams and rivulets', '400-1500m', '60000', false, false, 'Scaturigina loach is highly adapted to cool, well-oxygenated spring waters.'),
('panjab-loach', 'Panjab Loach', 'Nemacheilus panjabensis', 'A small stone loach found in tributaries of the Karnali and Gandaki rivers.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Hill streams with gravel substrate', '300-2000m', '100000', false, false, 'Panjab loach is part of a species complex still being revised by taxonomists.'),
('green-loach', 'Green Loach', 'Nemacheilus chlorosoma', 'A small loach with greenish coloration, found in clear streams of eastern Nepal.', 'FISH', 'DATA_DEFICIENT', 'COMMON', 'Clear streams in eastern hills', '200-1200m', '40000', false, false, 'Green loach is well-camouflaged against algae-covered rocks.'),
('thermal-loach', 'Thermal Loach', 'Lepidocephalichthys thermalis', 'A small loach tolerant of warm and even slightly thermal waters.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Warm streams, rice paddies, and thermal springs', '50-500m', '180000', false, false, 'Thermal loach can tolerate water temperatures up to 38 degrees Celsius.'),
('guntea-loach', 'Guntea Loach', 'Lepidocephalichthys guntea', 'A small loach found in slow-moving waters of the Terai and lower hills.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Ponds, ditches, and slow streams', '50-800m', '200000', false, false, 'Guntea loach is commonly sold as live fish food in the aquarium trade.'),
('gongota-loach', 'Gongota Loach', 'Somileptes gongota', 'A rare loach found in fast mountain streams with cobble substrate.', 'FISH', 'VULNERABLE', 'RARE', 'Fast mountain streams', '800-2000m', '15000', false, false, 'Gongota loach is highly sensitive to water pollution and habitat disturbance.'),
('striped-gourami', 'Striped Gourami', 'Colisa fasciata', 'A small labyrinth fish with dark vertical bars, found in warm lowland waters.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Ponds, ditches, and rice paddies', '50-500m', '250000', false, false, 'Striped gourami builds bubble nests for protecting its eggs.'),
('dwarf-gourami', 'Dwarf Gourami', 'Colisa lalia', 'A tiny, brilliantly colored labyrinth fish popular in the aquarium trade.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Warm slow-moving waters and vegetation', '50-400m', '200000', false, false, 'Male dwarf gouramis display vibrant orange and blue coloring during breeding.'),
('climbing-perch', 'Climbing Perch', 'Anabas testudineus', 'A hardy fish capable of breathing air and moving short distances on land.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Ponds, flooded fields, and slow streams', '50-500m', '300000', false, false, 'Climbing perch can survive out of water for several days by using its gill spines.'),
('oriental-snakehead', 'Oriental Snakehead', 'Channa orientalis', 'A small snakehead found in hill streams of eastern Nepal.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Hill streams and wetlands', '200-1500m', '120000', false, false, 'Oriental snakehead is one of the smaller snakehead species endemic to the region.'),
('redsnakehead', 'Red Snakehead', 'Channa marulioides', 'A large snakehead with reddish markings, found in rivers of the Terai.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Rivers and large ponds', '50-600m', '100000', false, false, 'Red snakehead is prized as a food fish and commands high prices in local markets.'),
('dwarf-gurami-badis', 'Badis', 'Badis badis', 'A small, color-changing fish that can shift between dark and light patterns.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Slow streams with vegetation', '100-800m', '150000', false, false, 'Badis can change color rapidly based on mood, territory, and breeding condition.'),
('giant-spiny-eel', 'Giant Spiny Eel', 'Mastacembelus armatus', 'A large eel-like fish with a distinctive elongated snout and dorsal spines.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Rivers and large streams', '50-800m', '120000', false, false, 'Giant spiny eel burrows into riverbed substrate and can be aggressive toward tankmates.'),
('pancalus-spiny-eel', 'Pancalus Spiny Eel', 'Mastacembelus pancalus', 'A small spiny eel found in warm waters of the Terai region.', 'FISH', 'LEAST_CONCERN', 'COMMON', 'Ponds, ditches, and slow rivers', '50-400m', '180000', false, false, 'Pancalus spiny eel is commonly caught in bamboo fish traps.'),
('common Mormon swallowtail', 'Common Mormon Swallowtail', 'Papilio polytes', 'A widespread swallowtail with multiple female forms mimicking other butterflies.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Gardens, forests, and agricultural areas', '100-2200m', '500000', false, false, 'Female common mormons can mimic at least eight different unpalatable species.'),
('red-base-swallowtail', 'Red-base Swallowtail', 'Papilio rumanzovia', 'A large swallowtail with distinctive red basal patches on its hindwings.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Tropical and subtropical forests', '200-1500m', '80000', false, false, 'Red-base swallowtail is one of the larger Papilio species found in Nepal.'),
('great-mormon', 'Great Mormon', 'Papilio memnon', 'A large, sexually dimorphic swallowtail with several female morphs.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Forests and cultivated areas', '100-1800m', '200000', false, false, 'Great mormon females can be tailless or tailed depending on the mimicry form.'),
('common-peacock-swallowtail', 'Common Peacock', 'Papilio bianor', 'A large swallowtail with brilliant blue-green iridescence on its wings.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Forests and forest edges', '200-2000m', '250000', true, false, 'Common peacock is named for the eye-like spots on its hindwings resembling a peacock feather.'),
('red-breasted-swallowtail', 'Red-breasted Swallowtail', 'Papilio protenor', 'A large dark swallowtail with red patches on the underside of the forewing.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Forests and forest edges', '200-2000m', '180000', false, false, 'Red-breasted swallowtail lacks tails unlike most other large Papilio species.'),
('old-world-swallowtail', 'Old World Swallowtail', 'Papilio machaon', 'A widely distributed swallowtail with yellow and black markings and blue tail spots.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Open grasslands and mountain meadows', '1000-4000m', '300000', false, false, 'Old world swallowtail is one of the most widespread butterfly species globally.'),
('arcturus-swallowtail', 'Arcturus Swallowtail', 'Papilio arcturus', 'A large swallowtail with blue-green dusting on dark wings.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Subtropical forests', '300-1800m', '60000', false, false, 'Arcturus swallowtail is named after the bright star Arcturus.'),
('common-mormon-swallowtail', 'Common Mormon', 'Papilio helenus', 'A large swallowtail with white patches on the forewing and red lunules.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Forests and gardens', '100-2000m', '200000', false, false, 'Common mormon gets its name from the polyandrous mating behavior of females.'),
('common-lime-butterfly', 'Common Lime Butterfly', 'Papilio demoleus', 'A widespread, tailless swallowtail with a checkerboard pattern.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Gardens, orchards, and urban areas', '50-1800m', '600000', false, false, 'Common lime butterfly is a major pest of citrus crops across South Asia.'),
('tiger-swallowtail', 'Tiger Swallowtail', 'Papilio bianor', 'A dark swallowtail with tiger-like stripes, found in hill forests.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Subtropical and temperate forests', '300-2500m', '200000', false, false, 'Tiger swallowtail caterpillars mimic snake heads to deter predators.'),
('red-swallowtail', 'Red Swallowtail', 'Papilio protenor', 'A dark swallowtail with crimson patches visible on the underwing.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Forests and scrublands', '200-1800m', '180000', false, false, 'Red swallowtail flies rapidly and is rarely seen at rest in the open.'),
('green-swallowtail', 'Green Swallowtail', 'Papilio paris', 'A forest-dwelling swallowtail with iridescent green scales.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Dense forests with canopy cover', '300-2000m', '160000', false, false, 'Green swallowtail males engage in hill-topping behavior to establish territories.'),
('yellow-base-tiger', 'Yellow-base Tiger', 'Delias hyparete', 'A white butterfly with yellow and red markings on the hindwing underside.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Open areas and forest edges', '100-1200m', '180000', false, false, 'Yellow-base tiger is part of the diverse Delias genus with many Himalayan species.'),
('small-white', 'Small White', 'Pieris canidia', 'A common white butterfly with small black spots on the wings.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Gardens, fields, and open areas', '50-2500m', '500000', false, false, 'Small white is one of the most frequently encountered butterflies in Nepal.'),
('large-cabbage-white', 'Large Cabbage White', 'Pieris brassicae', 'A large white butterfly that is a pest of brassica crops.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Agricultural fields and gardens', '100-3000m', '400000', false, false, 'Large cabbage white caterpillars can defoliate entire cabbage plants overnight.'),
('small-green-vein', 'Small Green Vein', 'Pontia daplidice', 'A small white butterfly with green veining on the hindwing underside.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Open grasslands and meadows', '500-3000m', '250000', false, false, 'Small green vein undertakes high-altitude migrations across the Himalayas.'),
('common-grass-yellow', 'Common Grass Yellow', 'Eurema hecabe', 'A small bright yellow butterfly common in grasslands and open areas.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Grasslands, gardens, and forest edges', '50-2000m', '600000', false, false, 'Common grass yellow shows seasonal color variation between wet and dry seasons.'),
('small-grass-yellow', 'Small Grass Yellow', 'Eurema blanda', 'A small yellow butterfly similar to E. hecabe but smaller in size.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Open areas and secondary growth', '50-1500m', '350000', false, false, 'Small grass yellow has a distinctive rounded forewing compared to its relatives.'),
('common-jezebel', 'Common Jezebel', 'Cepora nerissa', 'A white butterfly with yellow and black underside markings.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Gardens and open areas', '50-1500m', '300000', false, false, 'Common jezebel gets its biblical name from its bright warning coloration.'),
('yellow-orange-tip', 'Yellow Orange Tip', 'Ixias pyrene', 'A white butterfly with bright orange-yellow tips on the forewings.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Open scrublands and gardens', '100-1500m', '200000', false, false, 'Yellow orange tip males use UV-reflective wing patches to attract females.'),
('veined-orange-tip', 'Veined Orange Tip', 'Ixias venilia', 'An orange-tipped pierid with distinctive dark veining patterns.', 'BUTTERFLY', 'DATA_DEFICIENT', 'COMMON', 'Subtropical forests and scrublands', '200-1200m', '40000', false, false, 'Veined orange tip is rarely observed despite being widespread in suitable habitat.'),
('mountain-clouded-yellow', 'Mountain Clouded Yellow', 'Colias eogene', 'A high-altitude butterfly with orange-yellow wings and dark borders.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Alpine meadows and mountain slopes', '2500-4500m', '150000', false, false, 'Mountain clouded yellow is specially adapted to survive at extreme altitudes.'),
('dark-clouded-yellow', 'Dark Clouded Yellow', 'Colias fieldii', 'A dark-bordered yellow butterfly found in Himalayan foothills.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Mountain meadows and open slopes', '1500-3500m', '200000', false, false, 'Dark clouded yellow can fly at surprisingly low temperatures due to dark wing coloration.'),
('great-eggfly', 'Great Eggfly', 'Hypolimnas bolina', 'A striking butterfly with large white spots bordered by blue iridescence.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Forests, gardens, and open areas', '50-2000m', '250000', false, false, 'Female great eggflies can mimic several unpalatable species for protection.'),
('danaid-eggfly', 'Danaid Eggfly', 'Hypolimnas misippus', 'A sexually dimorphic butterfly where males are orange and females mimic plain tigers.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Open areas and gardens', '50-1200m', '200000', false, false, 'Male and female danaid eggflies look so different they were once thought separate species.'),
('pansy-butterfly', 'Pansy Butterfly', 'Junonia atlites', 'A gray-brown nymphalid with eyespots, common in open areas.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Open grasslands and gardens', '50-1500m', '300000', false, false, 'Pansy butterfly basks with wings spread flat to absorb maximum sunlight.'),
('lemon-pansy', 'Lemon Pansy', 'Junonia lemonias', 'A golden-brown butterfly with prominent eyespots on all wings.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Gardens, fields, and open areas', '50-1800m', '500000', false, false, 'Lemon pansy can rotate its eyespots to startle predators from different angles.'),
('blue-pansy', 'Blue Pansy', 'Junonia orithya', 'A butterfly with striking blue hindwings and orange forewings.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Open grasslands and scrublands', '50-1500m', '250000', false, false, 'Blue pansy males are highly territorial and chase away other butterflies.'),
('painted-lady', 'Painted Lady', 'Vanessa cardui', 'A cosmopolitan migrant butterfly found on every continent except Antarctica.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Open areas, gardens, and migration routes', '50-4000m', '1000000', false, false, 'Painted lady undertakes one of the longest insect migrations, up to 15000 km.'),
('red-admiral', 'Red Admiral', 'Vanessa indica', 'A dark butterfly with red-orange bands, common in Himalayan forests.', 'BUTTERFLY', 'LEAST_CONCERN', 'COMMON', 'Forests and orchards at various elevations', '500-3000m', '200000', false, false, 'Red admiral is known to migrate to high altitudes during summer months.'),
